#include<bits/stdc++.h>
using namespace std;

struct node{
    int a,b,c,ai,bi,i,ci;
}a[1005];
int n;
int cmp(node a,node b){
    if(a.c==b.c){
        return a.b>b.b;
    }else{
        return a.c>b.c;
    }
}
int cmp2(node a,node b){
    return a.i<b.i;

}
int cmp3(node a,node b){
    return a.a<b.a;

}
int cmp4(node a,node b){
    return a.b<b.b;

}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i].a;
    }
    for(int i=1;i<=n;i++){
        cin>>a[i].b;
        a[i].i=i;
    }
    sort(a+1,a+1+n,cmp3);
    for(int i=1;i<=n;i++){
        a[i].ai=i;
    }
    sort(a+1,a+1+n,cmp4);
    for(int i=1;i<=n;i++){
        a[i].bi=i;
        a[i].c=a[i].bi-a[i].ai;
    }
    sort(a+1,a+1+n,cmp);
    for(int i=1;i<=n;i++){
        a[i].ci=i;
    }
    sort(a+1,a+1+n,cmp2);
    for(int i=1;i<=n;i++){
        cout<<a[i].ci<< ' ';
    }
    return 0;
}
